CREATE TABLE IF NOT EXISTS users(id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE, password_hash VARCHAR(255), name VARCHAR(255), role VARCHAR(50) DEFAULT 'parent', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS donations(id SERIAL PRIMARY KEY, donor_name VARCHAR(255), donor_email VARCHAR(255), amount_usd NUMERIC(10,2), amount_ugx NUMERIC(14,2), stripe_payment_id VARCHAR(255), status VARCHAR(50) DEFAULT 'pending', platform_fee_percent NUMERIC(5,2) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS grant_proposals(id SERIAL PRIMARY KEY, title VARCHAR(255), funder_name VARCHAR(255), amount_requested_usd NUMERIC(12,2), amount_requested_ugx NUMERIC(14,2), problem_statement TEXT, solution_text TEXT, status VARCHAR(50) DEFAULT 'draft', ai_generated BOOLEAN DEFAULT false, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS donor_accounts(id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE, password_hash VARCHAR(255), name VARCHAR(255), total_donated_usd NUMERIC(12,2) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
